#include <bits/stdc++.h>
using namespace std;
int main() {
    map<string, int> freq;

    // ── Insert / Update ──
    freq["apple"]++;          // If key absent, default-initializes to 0, then ++
    freq["banana"] = 5;
    freq.insert({"cherry", 3});  // insert() does NOT overwrite existing keys
    freq["apple"]++;          // apple is now 2

    // ── Lookup ──
    cout << freq["banana"] << "\n";  // 5
    // WARNING: freq["grape"] creates the key with value 0!
    // Use .count() or .find() to check without inserting:
    if (freq.count("grape"))  cout << "exists\n";
    else                      cout << "not found\n";  // this prints

    auto it = freq.find("apple");
    if (it != freq.end()) {
        cout << it->first << ": " << it->second << "\n";  // apple: 2
    }

    // ── Erase ──
    freq.erase("banana");    // by key
    // freq.erase(it);       // by iterator — O(1) amortized

    // ── Iterate (always in sorted key order) ──
    for (auto& [key, val] : freq) {   // C++17 structured bindings
        cout << key << " -> " << val << "\n";
    }

    // ── Useful meta ──
    cout << freq.size() << "\n";   // number of pairs
    cout << freq.empty() << "\n";  // 0 or 1
    freq.clear();                  // remove all
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
int main() {
    set<int> s;

    // ── Insert ──
    s.insert(5);
    s.insert(3);
    s.insert(8);
    s.insert(3);  // Ignored — duplicates not stored
    // s = {3, 5, 8}

    // ── Lookup ──
    cout << s.count(5) << "\n";   // 1 (present)
    cout << s.count(7) << "\n";   // 0 (absent)

    // ── Nearest Neighbor (KEY CP PATTERN) ──
    auto it = s.lower_bound(6);   // First element >= 6: iterator to 8
    if (it != s.end())   cout << *it << "\n";  // 8
    if (it != s.begin()) { --it; cout << *it << "\n"; }  // 5 (largest < 6)

    // ── Erase ──
    s.erase(3);                   // by value
    s.erase(s.begin());           // erase smallest: 5
    // s = {8}

    // ── min/max in O(1) ──
    cout << *s.begin()  << "\n";  // smallest
    cout << *s.rbegin() << "\n"; // largest

    // ── Iterate ──
    for (int x : s) cout << x << " ";  // always sorted ascending
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
int main() {
    int n;
    cin >> n;
    vector<int> a(n);
    for (int& x : a) cin >> x;

    // Count frequencies in O(n) average
    unordered_map<int,int> freq;
    for (int x : a) freq[x]++;

    // Find the most frequent element
    int best_val = -1, best_cnt = 0;
    for (auto& [val, cnt] : freq) {
        if (cnt > best_cnt) {
            best_cnt = cnt;
            best_val = val;
        }
    }
    cout << best_val << " appears " << best_cnt << " times\n";

    // Two-Sum problem: O(n) with unordered_map
    int target;
    cin >> target;
    unordered_set<int> seen;
    for (int x : a) {
        if (seen.count(target - x)) {
            cout << "Pair found: " << x << " + " << (target-x) << "\n";
            break;
        }
        seen.insert(x);
    }
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
int main() {
    multiset<int> ms = {3, 1, 4, 1, 5, 9, 2, 6, 5, 3};
    // ms = {1, 1, 2, 3, 3, 4, 5, 5, 6, 9}

    // ── Count occurrences ──
    cout << ms.count(1) << "\n";   // 2
    cout << ms.count(7) << "\n";   // 0

    // ── CRITICAL: erase ONE element vs ALL ──
    ms.erase(1);                   // Removes ALL 1s!
    // ms = {2, 3, 3, 4, 5, 5, 6, 9}

    ms.insert(7);
    ms.erase(ms.find(3));          // Removes ONE 3 — this is the safe pattern
    // ms = {2, 3, 4, 5, 5, 6, 7, 9}

    // ── Sliding window median pattern: two multisets ──
    // lo holds the smaller half, hi holds the larger half
    multiset<int> lo, hi;
    auto get_median = [&]() -> double {
        if (lo.size() == hi.size()) return (*lo.rbegin() + *hi.begin()) / 2.0;
        return (lo.size() > hi.size()) ? *lo.rbegin() : *hi.begin();
    };
    (void)get_median; // suppress unused warning
    return 0;
}

// Given values up to 10^9, remap them to [0, k-1] for use as array indices
vector<int> a = {1000000, 5, 300, 5, 1000000, 42};

// Step 1: Get sorted unique values
vector<int> vals(a.begin(), a.end());
sort(vals.begin(), vals.end());
vals.erase(unique(vals.begin(), vals.end()), vals.end());
// vals = {5, 42, 300, 1000000} → indices 0,1,2,3

// Step 2: Compress using lower_bound
vector<int> compressed(a.size());
for (int i = 0; i < (int)a.size(); i++) {
    compressed[i] = lower_bound(vals.begin(), vals.end(), a[i]) - vals.begin();
}
// compressed = {3, 0, 2, 0, 3, 1}

// Group strings that are anagrams of each other
vector<string> words = {"eat", "tea", "tan", "ate", "nat", "bat"};
map<string, vector<string>> groups;
for (const string& w : words) {
    string key = w;
    sort(key.begin(), key.end());  // Canonical form: sorted chars
    groups[key].push_back(w);
}
for (auto& [key, grp] : groups) {
    for (const string& s : grp) cout << s << " ";
    cout << "\n";
}
// Output (order may vary by canonical key):
// ate eat tea
// bat
// nat tan

// Count number of distinct elements in each window of size k
vector<int> a = {1, 2, 1, 3, 2, 2, 1};
int k = 3;
map<int,int> window;   // value -> count in current window

// Initialize first window
for (int i = 0; i < k; i++) window[a[i]]++;
cout << window.size() << "\n";   // distinct count in first window

for (int i = k; i < (int)a.size(); i++) {
    // Add new element
    window[a[i]]++;
    // Remove leftmost element
    int left = a[i - k];
    window[left]--;
    if (window[left] == 0) window.erase(left);  // Remove key when count hits 0
    cout << window.size() << "\n";
}

