#include <bits/stdc++.h>
using namespace std;

void solve() {
    int n;
    cin >> n;
    vector<int> a(n);
    for (int& x : a) cin >> x;

    int q;
    cin >> q;
    while (q--) {
        int l, r;
        cin >> l >> r;

        map<int,int> freq;
        for (int i = l; i <= r; i++) freq[a[i]]++;

        int best_val = -1, best_cnt = 0;
        for (auto& [val, cnt] : freq) {
            // Map iterates in sorted key order;
            // first key with max count wins the tie.
            if (cnt > best_cnt) {
                best_cnt = cnt;
                best_val = val;
            }
        }
        cout << best_val << "\n";
    }
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int t; cin >> t;
    while (t--) solve();
    return 0;
}

