#include <bits/stdc++.h>
using namespace std;
int main() {
    map<int,int> m = {{1,5},{2,3},{3,8},{4,1},{5,6}};
    // Correct: erase() returns the next valid iterator
    for (auto it = m.begin(); it != m.end(); ) {
        if (it->second < 4) {
            it = m.erase(it);  // erase returns next valid iterator
        } else {
            ++it;
        }
    }
    for (auto& [k,v] : m) cout << k << ":" << v << " ";
    // Output: 1:5 3:8 5:6
    return 0;
}
